using ModelContextProtocol.Server;
using System.ComponentModel;

namespace HttpMcpServer.Tools;

[McpServerToolType]
public static class GreetingTools
{
    [McpServerTool, Description("Generates a personalized greeting message.")]
    public static string Greet(
        [Description("The name of the person to greet")] string name,
        [Description("Optional greeting style: formal or casual")] string style = "casual")
    {
        return style.ToLowerInvariant() switch
        {
            "formal" => $"Good day, {name}. It is a pleasure to make your acquaintance.",
            _ => $"Hey {name}, welcome aboard! đź‘‹"
        };
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

namespace HttpMcpServer.Resources;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxRequestsPerMinute = 60,
            Features = new { EnableCaching = true, EnableLogging = true }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://app/status",
        Name = "Server Status",
        MimeType = "application/json"),
     Description("Returns the current server status and uptime information.")]
    public static string GetServerStatus()
    {
        var status = new
        {
            Status = "healthy",
            StartedAt = Program.StartedAt,
            Uptime = DateTime.UtcNow - Program.StartedAt
        };

        return JsonSerializer.Serialize(status, new JsonSerializerOptions { WriteIndented = true });
    }
}

